# frozen_string_literal: true

require "yaml"
require "fileutils"
require_relative "dependency"

module Dev
  module Deps
    # Pure serialization: writes/reads Dependencies to/from YAML lockfiles.
    # No resolution logic — that's the Resolver's job.
    #
    # Two lockfiles, same format:
    #   deps.lock       — app + test groups
    #   build-deps.lock — build group (env-scoped deps nested under env:)
    class Locker
      HEADER = <<~COMMENT
        # Generated by dev. Do not edit.
        # Edit dependencies.rb and run dev update-deps to change.

      COMMENT

      DEPS_LOCK = "deps.lock"
      BUILD_DEPS_LOCK = "build-deps.lock"

      # Write dependencies to a single lockfile path.
      #
      # @param deps          [Array<Dependency>]
      # @param lockfile_path [String]
      def write(deps, lockfile_path:)
        FileUtils.mkdir_p(File.dirname(lockfile_path))
        yaml_hash = deps_to_yaml_hash(deps)
        File.write(lockfile_path, HEADER + YAML.dump(yaml_hash).delete_prefix("---\n"))
      end

      # Read dependencies from a single lockfile path.
      #
      # @param lockfile_path [String]
      # @return [Array<Dependency>]
      def read(lockfile_path:)
        return [] unless File.exist?(lockfile_path)

        yaml = YAML.safe_load(File.read(lockfile_path), permitted_classes: [Symbol])
        return [] if yaml.nil?

        yaml_hash_to_deps(yaml)
      end

      # Write dependencies to the appropriate lockfile based on group.
      # app/test → deps.lock, build → build-deps.lock
      #
      # @param deps [Array<Dependency>]
      # @param root [String] project root directory
      def write_for_groups(deps, root:)
        app_deps = deps.select { |d| d.group == :app || d.group == :test }
        build_deps = deps.select { |d| d.group == :build }

        write(app_deps, lockfile_path: File.join(root, DEPS_LOCK)) if app_deps.any?
        write_build_lockfile(build_deps, root: root) if build_deps.any?
      end

      private

      # Serialize dependencies into a flat YAML hash (name → attributes).
      def deps_to_yaml_hash(deps)
        result = {}
        deps.each do |dep|
          result[dep.name] = dep_to_hash(dep)
        end
        result
      end

      def dep_to_hash(dep)
        h = { "integration" => dep.integration.to_s, "group" => dep.group.to_s }
        h["version"] = dep.version if dep.version
        h["hash"] = dep.hash if dep.hash
        dep.metadata&.each { |k, v| h[k.to_s] = v } unless dep.metadata.nil? || dep.metadata.empty?
        h
      end

      # Parse a flat YAML hash back into Dependency objects.
      def yaml_hash_to_deps(yaml)
        deps = []

        yaml.each do |key, value|
          next unless value.is_a?(Hash)

          if key == "env"
            value.each do |env_name, env_deps|
              env_deps.each do |dep_name, attrs|
                deps << hash_to_dep(dep_name, attrs, env: env_name)
              end
            end
          else
            deps << hash_to_dep(key, value)
          end
        end

        deps
      end

      def hash_to_dep(name, attrs, env: nil)
        metadata = attrs.reject { |k, _| %w[integration group version hash].include?(k) }
        metadata["env"] = env if env

        Dependency.new(
          name: name,
          integration: attrs["integration"].to_sym,
          group: attrs["group"].to_sym,
          version: attrs["version"],
          hash: attrs["hash"],
          metadata: metadata.empty? ? {} : metadata,
        )
      end

      # Build lockfile has env-scoped deps nested under an env: section.
      def write_build_lockfile(deps, root:)
        global_deps = deps.select { |d| d.metadata.nil? || !d.metadata.key?("env") }
        env_deps = deps.select { |d| d.metadata&.key?("env") }

        yaml_hash = {}
        global_deps.each { |dep| yaml_hash[dep.name] = dep_to_hash(dep) }

        if env_deps.any?
          env_section = {}
          env_deps.each do |dep|
            env_name = dep.metadata["env"]
            env_section[env_name] ||= {}
            h = dep_to_hash(dep)
            h.delete("env")
            env_section[env_name][dep.name] = h
          end
          yaml_hash["env"] = env_section
        end

        lockfile_path = File.join(root, BUILD_DEPS_LOCK)
        FileUtils.mkdir_p(File.dirname(lockfile_path))
        File.write(lockfile_path, HEADER + YAML.dump(yaml_hash).delete_prefix("---\n"))
      end
    end
  end
end
